const tagContainer=document.getElementById("tag-container");fetch("/api/tags?sort=post_count&order=desc").then(response=>{response.json().then(json=>{json.data.forEach(tag=>{var tagListItem=document.createElement("li"),tagLink=document.createElement("a"),postCount=document.createElement("div");tagLink.href=`/posts/?tags=${tag.name}`,tagLink.innerText=tag.name,postCount.innerText=tag.post_count,tagLink.classList.add("tag-list-item"),tagListItem.classList.add(tag.type),tagListItem.appendChild(tagLink),tagListItem.appendChild(postCount),tagContainer.appendChild(tagListItem)})})});